1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("Claim Office", () => {
5	  describe("quote — base premiums and fee", () => {
6	    it("returns 5 G for an empty item list (processing fee only)", () => {
7	      expect(quote({ items: [] })).toBe(5);
8	    });
9	    it("returns 105 G for a single plain sword (100 base + 5 fee)", () => {
10	      expect(quote({ items: [{ type: "sword" }] })).toBe(105);
11	    });
12	    it.todo("returns 65 G for a single plain amulet (60 base + 5 fee)");
13	    it.todo("returns 85 G for a single plain staff (80 base + 5 fee)");
14	    it.todo("returns 45 G for a single plain potion (40 base + 5 fee)");
15	    it.todo("returns 30 G for a single rune (25 base + 5 fee)");
16	    it.todo("returns 30 G for a single moonstone (25 base + 5 fee)");
17	  });
18	
19	  describe("quote — component building blocks", () => {
20	    it.todo("returns 55 G for 2 runes (50 base + 5 fee)");
21	    it.todo("returns 65 G for 3 runes (60 base block + 5 fee)");
22	    it.todo("returns 105 G for 4 runes (100 base, no block + 5 fee)");
23	    it.todo("returns 180 G for 7 runes (175 base + 5 fee)");
24	    it.todo("returns 80 G for 2 runes + 1 moonstone (75 base, no block: different types + 5 fee)");
25	    it.todo("returns 125 G for 3 runes + 3 moonstones (120 base, two separate blocks + 5 fee)");
26	  });
27	
28	  describe("quote — item-specific modifiers", () => {
29	    it.todo("adds 50% curse surcharge to a cursed sword's base premium");
30	    it.todo("adds 30% high-enchantment surcharge to a sword with enchantment exactly 5");
31	    it.todo("does not add high-enchantment surcharge to a sword with enchantment 4");
32	    it.todo("applies both curse and high-enchantment surcharges to a cursed sword with enchantment 5");
33	  });
34	
35	  describe("quote — policy-wide modifiers", () => {
36	    it.todo("applies 20% loyalty discount for a customer with exactly 2 years with MHPCO");
37	    it.todo("does not apply loyalty discount for a customer with fewer than 2 years");
38	    it.todo("applies 10% first-insurance surcharge to each item in a quote regardless of history");
39	    it.todo("applies 15% follow-up discount on the customer's second quote in a scenario");
40	  });
41	
42	  describe("quote — modifier scope on multi-item policies", () => {
43	    it.todo("sums item base premiums into the policy base premium for a cursed sword and a plain amulet");
44	    it.todo("applies the curse surcharge to only the cursed item's base premium, not the policy total");
45	  });
46	
47	  describe("quote — rounding", () => {
48	    it.todo("rounds the final premium up to whole G (197.5 → 198)");
49	  });
50	
51	  describe("quote — integration examples", () => {
52	    it.todo("returns 165 G for a newcomer's cursed steel sword at enchantment 3");
53	    it.todo("returns 160 G for a long-standing customer's second-quote cursed steel sword at enchantment 7");
54	  });
55	
56	  describe("claim — standard reimbursement and deductible", () => {
57	    it.todo("pays 400 G for a steel sword enchantment 3 with 500 G damage (full minus 100 deductible)");
58	    it.todo("pays 100 G for a rune with 200 G damage (full minus 100 deductible)");
59	    it.todo("applies the 100 G deductible once per damaged item (sword 500 + amulet 300 → 600)");
60	  });
61	
62	  describe("claim — special clauses", () => {
63	    it.todo("reimburses 50% before deductible for a steel sword at enchantment 9 with 1000 G damage (→ 400)");
64	    it.todo("fully reimburses before deductible for a dragon sword at enchantment 5 with 800 G damage (→ 700)");
65	    it.todo("applies the 50% rule over dragon material for a dragon sword at enchantment 9 with 1000 G damage (→ 400)");
66	    it.todo("applies the high-enchantment clause for a dragon sword at exactly enchantment 8 with 1000 G damage (→ 400)");
67	  });
68	
69	  describe("claim — cap", () => {
70	    it.todo("caps total payout at twice the unmodified insurance sum");
71	    it.todo("reduces a claim to the remaining cap and reports remainingCap across successive claims (1500 → 1400 then 600)");
72	  });
73	
74	  describe("claim — rounding", () => {
75	    it.todo("rounds the final payout down to whole G (350.5 → 350)");
76	  });
77	});
